import { useEffect, useRef, useState } from 'react';
import { CONTACT } from '../data';

const ROLES = ['Full Stack Developer', 'MERN Stack Developer', 'React.js Developer'];

export default function Hero() {
  const [typed, setTyped]   = useState('');
  const roleIdx  = useRef(0);
  const charIdx  = useRef(0);
  const deleting = useRef(false);

  useEffect(() => {
    let timer;
    const tick = () => {
      const cur = ROLES[roleIdx.current];
      if (!deleting.current) {
        setTyped(cur.slice(0, charIdx.current + 1));
        charIdx.current++;
        if (charIdx.current === cur.length) {
          deleting.current = true;
          timer = setTimeout(tick, 1800);
          return;
        }
      } else {
        setTyped(cur.slice(0, charIdx.current - 1));
        charIdx.current--;
        if (charIdx.current === 0) {
          deleting.current = false;
          roleIdx.current  = (roleIdx.current + 1) % ROLES.length;
        }
      }
      timer = setTimeout(tick, deleting.current ? 50 : 90);
    };
    timer = setTimeout(tick, 400);
    return () => clearTimeout(timer);
  }, []);

  return (
    <section
      id="about"
      style={{
        minHeight: '100vh', display: 'flex', alignItems: 'center',
        justifyContent: 'center', padding: '6rem 2rem 4rem',
        position: 'relative', overflow: 'hidden',
      }}
    >
      {/* Background orbs */}
      <div style={{ position: 'absolute', inset: 0, pointerEvents: 'none' }}>
        <div style={{ position:'absolute', top:'20%', left:'10%', width:'380px', height:'380px', borderRadius:'50%', background:'radial-gradient(circle, rgba(79,142,247,0.08) 0%, transparent 70%)' }} />
        <div style={{ position:'absolute', bottom:'20%', right:'10%', width:'300px', height:'300px', borderRadius:'50%', background:'radial-gradient(circle, rgba(124,90,247,0.08) 0%, transparent 70%)' }} />
        <div style={{ position:'absolute', top:'50%', left:'50%', transform:'translate(-50%,-50%)', width:'600px', height:'600px', borderRadius:'50%', border:'1px solid rgba(79,142,247,0.06)' }} />
        <div style={{ position:'absolute', top:'50%', left:'50%', transform:'translate(-50%,-50%)', width:'900px', height:'900px', borderRadius:'50%', border:'1px solid rgba(79,142,247,0.03)' }} />
      </div>

      <div style={{ maxWidth: '720px', textAlign: 'center', position: 'relative' }}>
        {/* Profile Image */}
        <div style={{ animation: 'fadeUp 0.8s 0s ease both', marginBottom: '2.5rem' }}>
          <div style={{ 
            width: '180px', 
            height: '180px', 
            margin: '0 auto', 
            borderRadius: '50%', 
            padding: '5px',
            background: 'linear-gradient(135deg, var(--accent) 0%, var(--accent2) 100%)',
            boxShadow: '0 20px 40px rgba(0,0,0,0.3), 0 0 20px rgba(79,142,247,0.2)',
            position: 'relative'
          }}>
            <div style={{
              position: 'absolute',
              inset: '-10px',
              borderRadius: '50%',
              border: '2px solid rgba(79,142,247,0.1)',
              animation: 'pulse2 3s infinite'
            }} />
            <img 
              src="/sanjay.jpg" 
              alt="Sanjay" 
              style={{ 
                width: '100%', 
                height: '100%', 
                borderRadius: '50%', 
                objectFit: 'cover',
                border: '4px solid var(--bg)',
                backgroundColor: 'var(--surface2)'
              }} 
            />
          </div>
        </div>

        {/* Badge */}
        <div style={{ animation: 'fadeUp 0.8s 0.1s ease both' }}>
          <div style={{ display:'inline-flex', alignItems:'center', gap:'8px', background:'var(--surface2)', border:'1px solid var(--border)', borderRadius:'100px', padding:'6px 16px', marginBottom:'2rem', fontSize:'0.78rem', color:'var(--accent)', letterSpacing:'0.08em', textTransform:'uppercase' }}>
            <span style={{ width:'6px', height:'6px', borderRadius:'50%', background:'var(--green)', animation:'pulse2 2s infinite' }} />
            Available for opportunities
          </div>
        </div>

        {/* Name */}
        <div style={{ animation: 'fadeUp 0.8s 0.2s ease both' }}>
          <h1 style={{ fontFamily:'Syne', fontWeight:800, fontSize:'clamp(2.8rem,7vw,5.5rem)', lineHeight:1.05, letterSpacing:'-0.03em', marginBottom:'1.2rem' }}>
            Hi, I'm <span style={{ color:'var(--accent)' }}>Sanjay</span>
          </h1>
        </div>

        {/* Typewriter */}
        <div style={{ animation: 'fadeUp 0.8s 0.3s ease both' }}>
          <p style={{ fontFamily:'Syne', fontSize:'clamp(1.1rem,3vw,1.6rem)', fontWeight:600, color:'var(--muted)', marginBottom:'1.5rem', minHeight:'2.2rem' }}>
            <span style={{ color:'var(--accent2)' }}>{typed}</span>
            <span style={{ animation:'blink 1s step-end infinite', color:'var(--accent)' }}>|</span>
          </p>
        </div>

        {/* Tagline */}
        <div style={{ animation: 'fadeUp 0.8s 0.4s ease both' }}>
          <p style={{ color:'var(--muted)', lineHeight:1.75, fontSize:'1rem', maxWidth:'560px', margin:'0 auto 2.5rem' }}>
            Highly motivated full stack developer building innovative, user-centric web applications.
            MCA student at RVS College of Arts &amp; Science — passionate about the MERN stack and clean, maintainable code.
          </p>
        </div>

        {/* CTA Buttons */}
        <div style={{ animation:'fadeUp 0.8s 0.5s ease both', display:'flex', gap:'1rem', justifyContent:'center', flexWrap:'wrap' }}>
          <a href="#projects"
            style={{ padding:'0.8rem 2rem', background:'var(--accent)', color:'#fff', borderRadius:'8px', fontWeight:600, fontSize:'0.9rem', transition:'all 0.2s' }}
            onMouseEnter={(e) => (e.currentTarget.style.transform = 'translateY(-2px)')}
            onMouseLeave={(e) => (e.currentTarget.style.transform = 'none')}
          >
            View Projects
          </a>
          <a href="#contact"
            style={{ padding:'0.8rem 2rem', background:'transparent', color:'var(--text)', border:'1px solid var(--border)', borderRadius:'8px', fontWeight:600, fontSize:'0.9rem', transition:'all 0.2s' }}
            onMouseEnter={(e) => { e.currentTarget.style.borderColor='var(--accent)'; e.currentTarget.style.color='var(--accent)'; }}
            onMouseLeave={(e) => { e.currentTarget.style.borderColor='var(--border)'; e.currentTarget.style.color='var(--text)'; }}
          >
            Contact Me
          </a>
        </div>

        {/* Social links */}
        <div style={{ animation:'fadeUp 0.8s 0.6s ease both', marginTop:'3rem', display:'flex', gap:'2.5rem', justifyContent:'center', flexWrap:'wrap' }}>
          {[
            { label:'GitHub',   href: CONTACT.github },
            { label:'LinkedIn', href: CONTACT.linkedin },
            { label:'Email',    href: `mailto:${CONTACT.email}` },
          ].map(({ label, href }) => (
            <a key={label} href={href}
              style={{ fontSize:'0.82rem', color:'var(--muted)', letterSpacing:'0.05em', textTransform:'uppercase', borderBottom:'1px solid var(--border)', paddingBottom:'2px', transition:'all 0.2s' }}
              onMouseEnter={(e) => { e.currentTarget.style.color='var(--accent)'; e.currentTarget.style.borderColor='var(--accent)'; }}
              onMouseLeave={(e) => { e.currentTarget.style.color='var(--muted)';   e.currentTarget.style.borderColor='var(--border)'; }}
            >
              {label}
            </a>
          ))}
        </div>
      </div>
    </section>
  );
}
